+  }
+}
+
+/* ============================================
+   Glass morphism - exact match to reference
+   ============================================ */
+
+.glass {
+  background: oklch(0.14 0.02 260 / 0.8);
+  backdrop-filter: blur(12px);
+  -webkit-backdrop-filter: blur(12px);
+  border: 1px solid oklch(0.3 0.02 260 / 0.3);
+}
+
+.glass-subtle {
+  background: oklch(0.14 0.02 260 / 0.6);
+  backdrop-filter: blur(8px);
+  -webkit-backdrop-filter: blur(8px);
+}
+
+/* ============================================
+   Typography
+   ============================================ */
+
+h1, h2, h3, h4, h5, h6 {
+  font-weight: 600;
+  line-height: 1.3;
+  color: var(--foreground);
+  letter-spacing: -0.02em;
+}
+
+h1 { font-size: var(--text-2xl); }
+h2 { font-size: var(--text-xl); }
+h3 { font-size: var(--text-lg); }
+
+p {
+  margin-bottom: 1em;
+}
+p:last-child { margin-bottom: 0; }
+
+a {
+  color: var(--primary);
+  text-decoration: none;
+  transition: color var(--transition-fast);
+}
+
+a:hover {
+  color: oklch(0.85 0.18 195);
+  text-decoration: underline;
+}
+
+/* Inline code */
+code:not(pre code) {
+  font-family: 'JetBrains Mono', 'Fira Code', 'SF Mono', ui-monospace, monospace;
+  font-size: 0.875em;
+  padding: 0.125rem 0.375rem;
+  background: var(--secondary);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-sm);
+  color: var(--primary);
+  overflow-wrap: break-word;
+  word-break: break-word;
+}
+
+/* Code blocks */
+pre {
+  font-family: 'JetBrains Mono', 'Fira Code', 'SF Mono', ui-monospace, monospace;
+  font-size: 0.8125rem;
+  line-height: 1.7;
+  background: oklch(0.08 0.015 260);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-lg);
+  padding: var(--space-4);
+  overflow-x: auto;
+  margin: var(--space-4) 0;
+  max-width: 100%;
+}
+
+pre code {
+  padding: 0;
+  background: transparent;
+  border: none;
+  color: var(--foreground);
+  font-size: inherit;
+}
+
+/* Lists */
+ul, ol {
+  margin: var(--space-2) 0;
+  padding-left: 1.5em;
+}
+li {
+  margin-bottom: 0.25em;
+}
+li::marker { color: var(--muted-foreground); }
+
+/* Blockquotes */
+blockquote {
+  border-left: 3px solid var(--primary);
+  padding: var(--space-2) var(--space-4);
+  margin: var(--space-4) 0;
+  background: linear-gradient(90deg, oklch(0.75 0.18 195 / 0.05) 0%, transparent 100%);
+  border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
+  color: var(--secondary-foreground);
+}
+
+/* Tables */
+table {
+  width: 100%;
+  border-collapse: collapse;
+  margin: var(--space-4) 0;
+  font-size: 0.875rem;
+}
+th, td {
+  padding: var(--space-2) var(--space-3);
+  border: 1px solid var(--border);
+  text-align: left;
+}
+th {
+  background: var(--secondary);
+  font-weight: 600;
+  font-size: 0.75rem;
+  text-transform: uppercase;
+  letter-spacing: 0.5px;
+  color: var(--muted-foreground);
+}
+tr:hover td {
+  background: var(--muted);
+}
+
+
+/* ============================================
+   Header - Terminal Style
+   ============================================ */
+
+.header {
+  margin-bottom: var(--space-6);
+  padding: var(--space-4) var(--space-5);
+  background: var(--card);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-xl);
+  position: relative;
+}
+
+/* Terminal traffic lights */
+.header::before {
+  content: '';
+  position: absolute;
+  top: var(--space-4);
+  left: var(--space-5);
+  width: 12px;
+  height: 12px;
+  border-radius: 50%;
+  background: oklch(0.65 0.22 25);
+  box-shadow:
+    20px 0 0 oklch(0.78 0.16 75),
+    40px 0 0 oklch(0.72 0.19 145);
+}
+
+.header-content {
+  padding-left: 72px;
+}
+
+.header-title {
+  font-size: var(--text-lg);
+  font-weight: 600;
+  color: var(--foreground);
+  margin-bottom: var(--space-2);
+  line-height: 1.4;
+  font-family: 'Space Grotesk', 'IBM Plex Sans', sans-serif;
+}
+
+.header-meta {
+  display: flex;
+  flex-wrap: wrap;
+  align-items: center;
+  gap: var(--space-2) var(--space-4);
+  font-size: var(--text-sm);
+  color: var(--muted-foreground);
+}
+
+.header-meta span {
+  display: inline-flex;
+  align-items: center;
+  gap: 6px;
+}
+
+.header-agent {
+  color: var(--primary);
+  font-weight: 500;
+}
+
+.header-project {
+  font-family: 'JetBrains Mono', ui-monospace, monospace;
+  font-size: var(--text-xs);
+  padding: 0.25rem 0.625rem;
+  background: var(--secondary);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-sm);
+  color: var(--muted-foreground);
+}
+
+/* ============================================
+   Toolbar - Glassmorphic
+   ============================================ */
+
+.toolbar {
+  position: sticky;
+  top: var(--space-4);
+  z-index: 50;
+  display: flex;
+  align-items: center;
+  gap: var(--space-2);
+  padding: var(--space-3) var(--space-4);
+  margin-bottom: var(--space-6);
+  background: oklch(0.14 0.02 260 / 0.8);
+  backdrop-filter: blur(12px);
+  -webkit-backdrop-filter: blur(12px);
+  border: 1px solid oklch(0.3 0.02 260 / 0.3);
+  border-radius: var(--radius-xl);
+  box-shadow: var(--shadow-lg);
+  transition: all var(--transition-normal);
+}
+
+.toolbar:hover {
+  box-shadow: var(--shadow-xl), var(--shadow-glow-sm);
+}
+
+[data-theme="light"] .toolbar {
+  background: oklch(1 0 0 / 0.85);
+  border-color: var(--border);
+}
+
+.search-wrapper {
+  flex: 1;
+  position: relative;
+  min-width: 0;
+}
+
+.search-input {
+  width: 100%;
+  padding: 0.625rem 0.875rem;
+  padding-right: 3rem;
+  font-size: var(--text-sm);
+  color: var(--foreground);
+  background: var(--input);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-md);
+  outline: none;
+  transition: all var(--transition-fast);
+}
+
+.search-input::placeholder {
+  color: var(--muted-foreground);
+}
+
+.search-input:hover {
+  border-color: oklch(0.35 0.02 260);
+}
+
+.search-input:focus {
+  border-color: var(--primary);
+  box-shadow: 0 0 0 3px oklch(0.75 0.18 195 / 0.15), var(--shadow-glow-sm);
+}
+
+.search-count {
+  position: absolute;
+  right: 0.875rem;
+  top: 50%;
+  transform: translateY(-50%);
+  font-size: var(--text-xs);
+  font-weight: 500;
+  color: var(--muted-foreground);
+  background: var(--secondary);
+  padding: 0.125rem 0.375rem;
+  border-radius: var(--radius-sm);
+}
+
+.toolbar-btn {
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  width: var(--touch-min);
+  height: var(--touch-min);
+  min-width: var(--touch-min);
+  background: transparent;
+  border: 1px solid transparent;
+  border-radius: var(--radius-md);
+  color: var(--muted-foreground);
+  cursor: pointer;
+  transition: all var(--transition-fast);
+  position: relative;
+}
+
+.toolbar-btn:hover {
+  background: var(--secondary);
+  border-color: var(--border);
+  color: var(--foreground);
+}
+
+.toolbar-btn:active {
+  transform: scale(0.95);
+}
+
+.toolbar-btn svg {
+  width: 20px;
+  height: 20px;
+  transition: transform var(--transition-fast);
+}
+
+.toolbar-btn:hover svg {
+  transform: scale(1.1);
+}
+
+/* Theme toggle icon states */
+.icon-sun, .icon-moon {
+  transition: opacity var(--transition-fast), transform var(--transition-fast);
+}
+[data-theme="dark"] .icon-sun { opacity: 0; position: absolute; transform: rotate(90deg) scale(0.8); }
+[data-theme="dark"] .icon-moon { opacity: 1; }
+[data-theme="light"] .icon-sun { opacity: 1; }
+[data-theme="light"] .icon-moon { opacity: 0; position: absolute; transform: rotate(-90deg) scale(0.8); }
+
+/* ============================================
+   Messages - Card Based
+   ============================================ */
+
+.conversation {
+  display: flex;
+  flex-direction: column;
+  gap: var(--space-4);
+  position: relative;
+  z-index: 1;
+}
+
+/* Message wrapper - inherits conversation layout */
+.conversation-messages {
+  display: flex;
+  flex-direction: column;
+  gap: var(--space-4);
+}
+
+.message {
+  position: relative;
+  padding: var(--space-4) var(--space-5);
+  background: #1e1e28;
+  background: var(--card);
+  border: 1px solid #2d2d3a;
+  border: 1px solid var(--border);
+  border-radius: var(--radius-xl);
+  border-left: 4px solid #2d2d3a;
+  border-left: 4px solid var(--border);
+  transition: all var(--transition-fast);
+}
+
+.message:hover {
+  border-color: oklch(0.35 0.02 260);
+  box-shadow: var(--shadow-md);
+}
+
+.message.search-hit {
+  border-color: var(--primary);
+  box-shadow: var(--shadow-md), var(--shadow-glow-sm);
+}
+
+/* Role-specific styling */
+.message-user {
+  border-left-color: var(--green);
+}
+.message-user:hover {
+  box-shadow: var(--shadow-md), 0 0 30px -10px var(--green);
+}
+
+.message-assistant, .message-agent {
+  border-left-color: var(--primary);
+}
+.message-assistant:hover, .message-agent:hover {
+  box-shadow: var(--shadow-md), 0 0 30px -10px var(--primary);
+}
+
+.message-tool {
+  border-left-color: var(--amber);
+}
+.message-tool:hover {
+  box-shadow: var(--shadow-md), 0 0 30px -10px var(--amber);
+}
+
+.message-system {
+  border-left-color: var(--purple);
+  background: linear-gradient(135deg, var(--card) 0%, oklch(0.65 0.18 290 / 0.03) 100%);
+}
+
+.message-header {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  gap: var(--space-3);
+  margin-bottom: var(--space-3);
+  padding-bottom: var(--space-2);
+  border-bottom: 1px solid oklch(0.25 0.02 260 / 0.5);
+}
+
+.message-header-left {
+  display: flex;
+  align-items: center;
+  gap: var(--space-2);
+  min-width: 0;
+}
+
+.message-header-right {
+  display: flex;
+  flex-wrap: wrap;
+  align-items: center;
+  gap: var(--space-1);
+  flex-shrink: 0;
+}
+
+/* Lucide SVG icon styling */
+.lucide-icon {
+  display: inline-block;
+  vertical-align: middle;
+  flex-shrink: 0;
+}
+
+.lucide-spin {
+  animation: lucide-spin 1s linear infinite;
+}
+
+@keyframes lucide-spin {
+  from { transform: rotate(0deg); }
+  to { transform: rotate(360deg); }
+}
+
+.message-icon {
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  width: 24px;
+  height: 24px;
+  line-height: 1;
+}
+
+.message-icon .lucide-icon {
+  width: 16px;
+  height: 16px;
+}
+
+.message-author {
+  font-weight: 600;
+  font-size: var(--text-sm);
+  letter-spacing: -0.01em;
+}
+
+.message-user .message-author { color: var(--green); }
+.message-assistant .message-author, .message-agent .message-author { color: var(--primary); }
+.message-tool .message-author { color: var(--amber); }
+.message-system .message-author { color: var(--purple); }
+
+.message-time {
+  margin-left: auto;
+  font-size: var(--text-xs);
+  font-weight: 500;
+  color: var(--muted-foreground);
+  font-variant-numeric: tabular-nums;
+}
+
+.message-content {
+  font-size: var(--text-base);
+  line-height: 1.7;
+  color: var(--secondary-foreground);
+}
+
+.message-content > *:first-child { margin-top: 0; }
+.message-content > *:last-child { margin-bottom: 0; }
+
+/* Message content typography */
+.message-content p { margin-bottom: 0.85em; }
+.message-content h1, .message-content h2, .message-content h3 {
+  margin-top: 1.25em;
+  margin-bottom: 0.5em;
+  font-weight: 600;
+  color: var(--foreground);
+}
+.message-content h1 { font-size: 1.25rem; }
+.message-content h2 { font-size: 1.125rem; }
+.message-content h3 { font-size: 1rem; }
+.message-content ul, .message-content ol {
+  margin: 0.5em 0;
+  padding-left: 1.25em;
+}
+.message-content li { margin-bottom: 0.25em; }
+.message-content li::marker { color: var(--muted-foreground); }
+.message-content strong { color: var(--foreground); font-weight: 600; }
+
+/* Message link button */
+.message-link {
+  position: absolute;
+  top: var(--space-4);
+  right: var(--space-4);
+  opacity: 0;
+  padding: 6px;
+  background: var(--secondary);
+  border: 1px solid var(--border);
+  border-radius: var(--radius-sm);
+  color: var(--muted-foreground);
+  cursor: pointer;
+  transition: all var(--transition-fast);
+}
+
+.message:hover .message-link { opacity: 1; }
+.message-link:hover {
+  color: var(--primary);
+  border-color: var(--primary);
+  box-shadow: var(--shadow-glow-sm);
+}
+.message-link.copied {
+  color: var(--green);
+  border-color: var(--green);
+}
+
+/* ============================================
+   Tool Calls - Collapsible
+   ============================================ */
+
+/* Tool Badge - Compact inline badges with hover popovers */
+.tool-badges {
+  display: flex;
+  flex-wrap: wrap;
+  align-items: center;
+  gap: 4px;
+}
+
+.tool-badge {
+  position: relative;
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
+  min-width: 24px;
+  height: 24px;
+  padding: 0 4px;
+  font-size: 0.6875rem;
+  font-family: 'JetBrains Mono', ui-monospace, monospace;
+  background: transparent;
+  appearance: none;
+  -webkit-appearance: none;
+  border: 1px solid oklch(0.3 0.02 260 / 0.5);
+  border-radius: 6px;
+  cursor: pointer;
+  transition: all var(--transition-fast);
+  white-space: nowrap;
+  color: var(--amber);
+}
+
+.tool-badge:hover,
+.tool-badge:focus {
+  background: oklch(0.78 0.16 75 / 0.15);
+  border-color: var(--amber);
+  transform: scale(1.1);
+  outline: none;
+  box-shadow: var(--shadow-glow-amber);
+}
+
+.tool-badge:focus-visible {
+  box-shadow: 0 0 0 2px var(--primary);
+}
+
+.tool-badge-icon {
+  display: flex;
+  align-items: center;
+  justify-content: center;
+}
+
+.tool-badge-icon .lucide-icon {
+  width: 14px;
+  height: 14px;
+  stroke-width: 2;
+}
+
+.tool-badge-status {
+  display: inline-flex;
+  align-items: center;
+  justify-content: center;
+  position: absolute;
+  top: 2px;
+  right: 2px;
+  width: 6px;
+  height: 6px;
+  border-radius: 50%;
+  padding: 0;
+}
+
+.tool-badge-status .lucide-icon {
+  display: none;
+}
+
+/* Status-based badge styling with subtle left accent */
+.tool-badge.tool-status-success { border-color: var(--green); }
+.tool-badge.tool-status-error { border-color: var(--red); }
+.tool-badge.tool-status-pending { border-color: var(--amber); }
+
+.tool-badge.tool-status-success:hover { box-shadow: 0 4px 20px oklch(0.72 0.19 145 / 0.35); }
+.tool-badge.tool-status-error:hover { box-shadow: 0 4px 20px oklch(0.65 0.22 25 / 0.35); }
+
+.tool-badge-status.success { background: oklch(0.72 0.19 145 / 0.8); }
+.tool-badge-status.error { background: oklch(0.65 0.22 25 / 0.85); }
+.tool-badge-status.pending { background: oklch(0.78 0.16 75 / 0.85); }
+
+/* Overflow badge - "+X more" */
+.tool-badge.tool-overflow {
+  min-width: auto;
+  padding: 0 8px;
+  font-size: 0.6875rem;
+  font-weight: 600;
+  color: var(--muted-foreground);
+  border-style: dashed;
+}
+
+.tool-badge.tool-overflow:hover {
+  color: var(--foreground);
+  border-style: solid;
+}
+
+/* Expanded state for overflow - show all badges */
+.message-header-right.expanded .tool-badge {
+  display: inline-flex;
+}
+
+.message-header-right.expanded .tool-overflow {
+  order: 999; /* Move to end */
+}
+
+/* Popover - Glassmorphic with fixed positioning */
+.tool-popover {
+  position: absolute;
+  z-index: 1000;
+  min-width: 280px;
+  max-width: 400px;
+  max-height: 300px;
+  overflow: auto;
+  padding: var(--space-3);
+  background: oklch(0.14 0.02 260 / 0.95);
+  backdrop-filter: blur(16px);
+  -webkit-backdrop-filter: blur(16px);
+  border: 1px solid oklch(0.3 0.02 260 / 0.5);
+  border-radius: var(--radius-lg);
+  box-shadow: var(--shadow-xl), var(--shadow-glow-sm);
+  opacity: 0;
+  visibility: hidden;
+  transform: translateY(-4px);
+  transition: all 0.15s ease-out;
+  pointer-events: none;
+  text-align: left;
+  white-space: normal;
+  top: calc(100% + 8px);
+  left: 0;
+}
+
+.tool-popover.visible {
+  opacity: 1;
+  visibility: visible;
+  transform: translateY(0);
+  pointer-events: auto;
+}
+
+/* Fallback: show popover on hover/focus even if JS fails */
+.tool-badge:hover .tool-popover,
+.tool-badge:focus-within .tool-popover {
+  opacity: 1;
+  visibility: visible;
+  transform: translateY(0);
+  pointer-events: auto;
+}
+
+/* Light theme popover */
+[data-theme="light"] .tool-popover {
+  background: oklch(1 0 0 / 0.95);
+  border-color: var(--border);
+  box-shadow: 0 8px 32px oklch(0 0 0 / 0.15);
+}
+
+/* Arrow indicator (CSS-only, optional) */
+.tool-popover::before {
+  content: '';
+  position: absolute;
+  top: -6px;
+  left: 20px;
+  width: 12px;
+  height: 12px;
+  background: inherit;
+  border: inherit;
+  border-right: none;
+  border-bottom: none;
+  transform: rotate(45deg);
+  pointer-events: none;
+}
+
+.tool-popover.popover-above::before {
+  top: auto;
+  bottom: -6px;
+  transform: rotate(225deg);
+}
+
+.tool-popover-header {
+  display: flex;
+  align-items: center;
+  gap: var(--space-2);
+  padding-bottom: var(--space-2);
+  margin-bottom: var(--space-2);
+  border-bottom: 1px solid var(--border);
+  font-weight: 600;
+  color: var(--amber);
+}
+
+.tool-popover-header .lucide-icon {
+  width: 14px;
+  height: 14px;
+  flex-shrink: 0;
+}
+
+.tool-popover-header span {
+  overflow: hidden;
+  text-overflow: ellipsis;
+  white-space: nowrap;
+}
+
+.tool-popover-section {
+  margin-bottom: var(--space-2);
+}
+.tool-popover-section:last-child { margin-bottom: 0; }
+
+.tool-popover-label {
+  font-size: 0.5625rem;
+  font-weight: 700;
+  text-transform: uppercase;
+  letter-spacing: 0.8px;
+  color: var(--muted-foreground);
+  margin-bottom: 0.25rem;
+}
+
+.tool-popover pre {
+  margin: 0;
+  padding: var(--space-2);
+  font-size: 0.625rem;
+  background: var(--secondary);
+  border-radius: var(--radius-sm);
+  max-height: 150px;
+  overflow: auto;
+  white-space: pre-wrap;
+  word-break: break-word;
+}
+
+.tool-truncated {
+  font-size: 0.5625rem;
+  color: var(--amber);
+  margin-top: 0.25rem;
+  font-weight: 500;
+  font-style: italic;
+}
+
+/* ============================================
+   Floating Navigation
+   ============================================ */
+
+.floating-nav {
+  position: fixed;
+  bottom: calc(24px + env(safe-area-inset-bottom, 0px));
+  right: 24px;
+  display: flex;
+  flex-direction: column;
+  gap: var(--space-2);
+  opacity: 0;
+  transform: translateY(20px) scale(0.9);
+  transition: all var(--transition-normal);
+  pointer-events: none;
+  z-index: 100;
+}
+
+.floating-nav.visible {
+  opacity: 1;
+  transform: translateY(0) scale(1);
+  pointer-events: auto;
+}
+
+.floating-btn {
+  width: 48px;
+  height: 48px;
+  display: flex;
+  align-items: center;
+  justify-content: center;
+  background: oklch(0.14 0.02 260 / 0.8);
+  backdrop-filter: blur(12px);
+  -webkit-backdrop-filter: blur(12px);
+  border: 1px solid oklch(0.3 0.02 260 / 0.3);
+  border-radius: var(--radius-xl);
+  color: var(--muted-foreground);
